import * as Schema from 'effect/Schema';

import { DXN, Annotation, Type } from '@dxos/echo';

/**
 * Unit of knowledge generated by an agent.
 */
export const Memory = Schema.Struct({
  title: Schema.String,
  content: Schema.String,
}).pipe(
  Annotation.LabelAnnotation.set(['title']),
  Annotation.IconAnnotation.set({ icon: 'ph--brain--regular', hue: 'pink' }),
  Annotation.HiddenAnnotation.set(true),
  Type.makeObject(DXN.make('org.dxos.type.memory', '0.1.0')),
);

export type Memory = Type.InstanceType<typeof Memory>;
